// in this file one can find the vectorized versions (AVX256):
// 1. vectorized versions of the unroled code
// 2. a vectorized version of the tree acumulator code

// two parts once for int8 and once for float
// wrapper functions at the end of the file

//
// INT8 VERSIONS
//

// UNROLLING VERSIONS 
vector<int8_t> ssr_inference_int8_vec_unroll8_v2(
    const vector<int8_t>& v,
    const vector<int>& permutations_pos,
    const vector<int>& segments_pos,
    const vector<int>& permutations_neg,
    const vector<int>& segments_neg,
    int L, int M, int N, int K) {

    N = N + (L - N % L) % L;
    int num_blocks = N / L;
    int num_bins = 1 << L;
    vector<int8_t> result(K * N);

    // Create completely separate seg_sum arrays for each vector group (like scalar)
    vector<__m256i> seg_sum_0(2 * (num_bins - 1));


    // Main unrolled loop
    int unrolled_limit = K - (K % (1 * 32));
#pragma omp parallel for 
    for (int row = 0; row < unrolled_limit; row += 1 * 32) {
        // Working memory
        alignas(32) int8_t gather_buffer[32];
        alignas(32) int8_t temp_result[32];

        for (int b_idx = 0; b_idx < num_blocks; ++b_idx) {

            // Step 1: Declare variables for all 1 vector groups
            __m256i sum_pos_0, sum_neg_0;

            int len = num_bins - 1;
            int start_pos = segments_pos[b_idx * num_bins];
            int start_neg = segments_neg[b_idx * num_bins];

            // Step 2: Segmented sum for all vector groups simultaneously
            for (int bin = 0; bin < len; ++bin) {
                int end_pos = segments_pos[b_idx * num_bins + bin + 1];
                int end_neg = segments_neg[b_idx * num_bins + bin + 1];

                sum_pos_0 = _mm256_setzero_si256();
                sum_neg_0 = _mm256_setzero_si256();

                // Compute sums for all vector groups in parallel
                for (int i = start_pos; i < end_pos; ++i) {
                    int col_idx = permutations_pos[b_idx * M + i];

                    // Vector group 0
                    for (int j = 0; j < 32; ++j) {
                        gather_buffer[j] = v[(row + 0 + j) * M + col_idx];
                    }
                    __m256i vec_0 = _mm256_load_si256((__m256i*)gather_buffer);
                    sum_pos_0 = _mm256_add_epi8(sum_pos_0, vec_0);
                }

                for (int i = start_neg; i < end_neg; ++i) {
                    int col_idx = permutations_neg[b_idx * M + i];

                    // Vector group 0
                    for (int j = 0; j < 32; ++j) {
                        gather_buffer[j] = v[(row + 0 + j) * M + col_idx];
                    }
                    __m256i vec_0 = _mm256_load_si256((__m256i*)gather_buffer);
                    sum_neg_0 = _mm256_add_epi8(sum_neg_0, vec_0);
                }

                // Store results for all vector groups
                seg_sum_0[bin] = sum_pos_0;
                seg_sum_0[num_bins - 1 + bin] = sum_neg_0;

                start_pos = end_pos;
                start_neg = end_neg;
            }

            // Step 3: RSR++ reduction
            int len_0 = len;

            for (int j = L - 1; j >= 0; --j) {
                // Process vector group 0 with independent length len_0
                __m256i sum_pos_0 = seg_sum_0[0];
                __m256i sum_neg_0 = seg_sum_0[num_bins - 1];

                int new_len_0 = len_0 / 2;
                for (int idx = 0; idx < new_len_0; ++idx) {
                    sum_pos_0 = _mm256_add_epi8(sum_pos_0, seg_sum_0[02 * idx + 2]);
                    sum_neg_0 = _mm256_add_epi8(sum_neg_0, seg_sum_0[num_bins - 1 + 2 * idx + 2]);
                    seg_sum_0[idx] = _mm256_add_epi8(seg_sum_0[2 * idx + 1], seg_sum_0[2 * idx + 2]);
                    seg_sum_0[num_bins - 1 + idx] = _mm256_add_epi8(seg_sum_0[num_bins - 1 + 2 * idx + 1], seg_sum_0[num_bins - 1 + 2 * idx + 2]);
                }

                __m256i result_0 = _mm256_sub_epi8(sum_pos_0, sum_neg_0);
                _mm256_store_si256((__m256i*)temp_result, result_0);

                // Store final result for vector group 0
                for (int elem = 0; elem < 32; ++elem) {
                    result[(row + 0 + elem) * N + b_idx * L + j] = temp_result[elem];
                }

                len_0 = new_len_0;
            }
        }
    }

    // Cleanup: Process remaining rows one by one (exactly like scalar version)
    vector<int8_t> seg_sum(2 * (num_bins - 1));
#pragma omp parallel for 
    for (int row = unrolled_limit; row < K; ++row) {
        int output_offset = 0;

        for (int b_idx = 0; b_idx < num_blocks; ++b_idx) {

            int8_t sum_pos, sum_neg;
            int len = num_bins - 1;
            int start_pos = segments_pos[b_idx * num_bins];
            int start_neg = segments_neg[b_idx * num_bins];

            // Segmented sum
            for (int bin = 0; bin < len; ++bin) {
                int end_pos = segments_pos[b_idx * num_bins + bin + 1];
                int end_neg = segments_neg[b_idx * num_bins + bin + 1];

                sum_pos = 0;
                sum_neg = 0;
                for (int i = start_pos; i < end_pos; ++i) {
                    sum_pos += v[row * M + permutations_pos[b_idx * M + i]];
                }
                for (int i = start_neg; i < end_neg; ++i) {
                    sum_neg += v[row * M + permutations_neg[b_idx * M + i]];
                }
                seg_sum[bin] = sum_pos;
                seg_sum[num_bins - 1 + bin] = sum_neg;
                start_pos = end_pos;
                start_neg = end_neg;
            }

            // RSR++ reduction - EXACT same pattern as scalar
            for (int j = L - 1; j >= 0; --j) {
                int8_t sum_pos = seg_sum[0];
                int8_t sum_neg = seg_sum[num_bins - 1];
                int new_len = len / 2;
                for (int i = 0; i < new_len; ++i) {
                    sum_pos += seg_sum[2 * i + 2];
                    sum_neg += seg_sum[num_bins - 1 + 2 * i + 2];
                    seg_sum[i] = seg_sum[2 * i + 1] + seg_sum[2 * i + 2];
                    seg_sum[num_bins - 1 + i] = seg_sum[num_bins - 1 + 2 * i + 1] + seg_sum[num_bins - 1 + 2 * i + 2];
                }
                result[row * N + output_offset + j] = sum_pos - sum_neg;
                len = new_len;
            }

            output_offset += L;
        }
    }

    return result;
}

// unroling factor 32 (used to fill the vector length)
//version 1:
