    // Create separate seg_sum arrays for each unrolled vector group (exactly like scalar)
    vector<vector<__m256i>> seg_sum_0(2, vector<__m256i>(num_bins-1));
    vector<vector<__m256i>> seg_sum_1(2, vector<__m256i>(num_bins-1));
