    vector<vector<__m256i>> seg_sum_13(2, vector<__m256i>(num_bins-1));
    vector<vector<__m256i>> seg_sum_14(2, vector<__m256i>(num_bins-1));
    vector<vector<__m256i>> seg_sum_15(2, vector<__m256i>(num_bins-1));
    vector<vector<__m256i>> seg_sum_16(2, vector<__m256i>(num_bins-1));
    vector<vector<__m256i>> seg_sum_17(2, vector<__m256i>(num_bins-1));
    vector<vector<__m256i>> seg_sum_18(2, vector<__m256i>(num_bins-1));
