                __m256i vec = _mm256_set_epi8(v31[idx], v30[idx], v29[idx], v28[idx], v27[idx], v26[idx], v25[idx], v24[idx], v23[idx], v22[idx], v21[idx], v20[idx], v19[idx], v18[idx], v17[idx], v16[idx], v15[idx], v14[idx], v13[idx], v12[idx], v11[idx], v10[idx], v9[idx], v8[idx], v7[idx], v6[idx], v5[idx], v4[idx], v3[idx], v2[idx], v1[idx], v0[idx]);
                acc1_neg = _mm256_add_epi8(acc1_neg, vec);
