//
// Wrapper functions for calling correct function based on L factor
//

vector<int8_t> ssr_inference_int8_vec_tree(
    const vector<int8_t>& v,
    const vector<int>& permutations_pos,
    const vector<int>& segments_pos,
    const vector<int>& permutations_neg,
    const vector<int>& segments_neg,
    const int M, const int K, const int N, const int selectedL)
{
    if (selectedL == 2) {
        return ssr_inference_int8_vec_L2(v, permutations_pos, segments_pos, permutations_neg, segments_neg, K, N, M);
    }
    else if (selectedL == 3) {
        return ssr_inference_int8_vec_L3(v, permutations_pos, segments_pos, permutations_neg, segments_neg, K, N, M);
    }
    else if (selectedL == 4) {
        return ssr_inference_int8_vec_L4(v, permutations_pos, segments_pos, permutations_neg, segments_neg, K, N, M);
    }
    else if (selectedL == 5) {
        return ssr_inference_int8_vec_L5(v, permutations_pos, segments_pos, permutations_neg, segments_neg, K, N, M);
    }
    else /*if (selectedL == 6)*/ { // L capped at 6 for faster compile time while testing
        return ssr_inference_int8_vec_L6(v, permutations_pos, segments_pos, permutations_neg, segments_neg, K, N, M);
    }
    /*
    else if (selectedL == 7) {
        return ssr_inference_int8_vec_L7(v, permutations_pos, segments_pos, permutations_neg, segments_neg, K, N, M);
    }
    else {
        return ssr_inference_int8_vec_L8(v, permutations_pos, segments_pos, permutations_neg, segments_neg, K, N, M);
    }
    */

}

